import{_ as a,o,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"15. Professional Development Leave","description":"","frontmatter":{"title":"15. Professional Development Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","education-pd"]},"headers":[],"relativePath":"ebas/has-managers-admin/managers-admin/education-pd/15-professional-development-leave.md","filePath":"ebas/has-managers-admin/managers-admin/education-pd/15-professional-development-leave.md"}'),t={name:"ebas/has-managers-admin/managers-admin/education-pd/15-professional-development-leave.md"};function l(r,e,i,p,m,d){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_15-professional-development-leave" tabindex="-1">15. Professional Development Leave <a class="header-anchor" href="#_15-professional-development-leave" aria-label="Permalink to &quot;15. Professional Development Leave&quot;">​</a></h1><p>This clause only applies to Managers and Administrative Workers employed by Royal Women’s Hospital or Royal Children’s Hospital.</p><p><strong>15.1</strong> In recognition of the importance of ongoing professional development, an Employee may seek approval for 5 days paid professional leave, to attend a conference, seminar, workshop etc approved by the Employer.</p><p><strong>15.2</strong> Professional development leave is non cumulative.</p><p><strong>15.3</strong> The Employer will not unreasonably withhold authorisation for Professional Development leave.</p><p><strong>15.4</strong> Professional development leave must be clearly linked to the Employee’s profession and may include a requirement to report back to other staff.</p><p>PART F – CLASSIFICATION AND STAFFING</p><p>Plain language terms: PD leave, training leave.</p>',8)])])}const c=a(t,[["render",l]]);export{f as __pageData,c as default};
